import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read entire line including spaces

        int maxLength = 10; // Maximum length for buffer
        char[] buffer = new char[maxLength];

        int length = Math.min(name.length(), maxLength); // Ensure name does not exceed buffer size

        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Hello, " + new String(buffer, 0, length));
    }
}

### Explanation:
취약유형: Buffer Overflow
